/**
 * Sleeps for the specified timeout.
 *
 * @param {number} timeout - The timeout in milliseconds.
 * @returns {Promise<void>} A promise that resolves after the timeout.
 */
export async function sleep(timeout: number): Promise<void> {
    await new Promise((resolve) => setTimeout(resolve, timeout))
}

/**
 * Gets the package manager used in the project.
 *
 * @param {string} [cwd] - The current working directory.
 * @returns {'yarn' | 'npm' | 'pnpm'} The package manager used in the project.
 * @throws {Error} If no package manager is found.
 */
export function getProjectPackageManager(cwd?: string): 'yarn' | 'npm' | 'pnpm' {
    const yarn = findUpSync('yarn.lock', { cwd })
    if (yarn !== undefined) return 'yarn'

    const npm = findUpSync('package-lock.json', { cwd })
    if (npm !== undefined) return 'npm'

    // pnpm
    const pnpm = findUpSync('pnpm-lock.yaml', { cwd })
    if (pnpm !== undefined) return 'pnpm'

    throw new Error('Cannot find package.json or yarn.lock')
}

/**
 * Gets the root directory of the project.
 *
 * @param {string} [cwd] - The current working directory.
 * @returns {string} The root directory of the project.
 * @throws {Error} If no root directory is found.
 */
export function getProjectRootDir(cwd?: string): string {
    const yarn = findUpSync('yarn.lock', { cwd })
    if (yarn !== undefined) return path.dirname(yarn)

    const npm = findUpSync('package-lock.json', { cwd })
    if (npm !== undefined) return path.dirname(npm)

    const pnpm = findUpSync('pnpm-lock.yaml', { cwd })
    if (pnpm !== undefined) return path.dirname(pnpm)

    throw new Error('Cannot find yarn.lock or package-lock.json or pnpm-lock.yaml')
}

/**
 * Checks if an HTTP service is reachable.
 *
 * @param {string} host - The host of the HTTP service.
 * @param {number} port - The port of the HTTP service.
 * @param {number} timeout - The timeout in milliseconds.
 * @param {string} [path] - The path to check.
 * @returns {Promise<boolean>} A promise that resolves to true if the service is reachable, false otherwise.
 */
export async function isHttpServiceReachable(
    host: string,
    port: number,
    timeout: number,
    path?: string
): Promise<boolean> {
    return new Promise((resolve, _reject) => {
        const options: RequestOptions = {
            host,
            port,
            timeout,
            path,
            method: 'HEAD',
        }

        const request = http.request(options, (_response) => {
            resolve(true)
        })

        request.on('error', (_err) => {
            resolve(false)
        })

        request.end()
    })
}

/**
 * Extracts information from a URL.
 *
 * @param {string} url - The URL to extract information from.
 * @returns {{ schema: 'http' | 'https'; host: string; port: string }} An object containing the schema, host, and port.
 * @throws {Error} If the URL is invalid.
 */
export function extractUrlInfo(url: string): {
    schema: 'http' | 'https'
    host: string
    port: string
} {
    //TODO: handle the default port for http and https(443, 80)
    const m = url.match(/(?<schema>http|https):\/\/(?<host>.*):(?<port>\d+)/)
    if (m?.groups?.host === undefined) {
        throw new Error(`Invalid url ${url}`)
    }

    return {
        schema: m.groups.schema as 'http' | 'https',
        host: m.groups.host,
        port: m.groups.port,
    }
}
