import * as fs from 'fs'
import * as path from 'path'

type FindUpReturnType<T> = T extends string ? string | undefined : string[]

/**
 * Finds files in the current directory and its parent directories.
 *
 * @param {string | string[]} expectations - The expected file names.
 * @param {object} options - Options for the search.
 * @param {string} [options.cwd] - The current working directory.
 * @returns {FindUpReturnType<T>} An array of file paths that match the expectations or a single file path or undefined.
 */
export function findUp<T extends string | string[]>(
    expectations: T,
    options: { cwd?: string } = {}
): FindUpReturnType<T> {
    const expectationSet = new Set(Array.isArray(expectations) ? expectations : [expectations])
    if (expectationSet.size === 0) {
        return (Array.isArray(expectations) ? [] : undefined) as FindUpReturnType<T>
    }

    const cwd = options.cwd ?? process.cwd()
    let currentDir = cwd

    while (currentDir !== '/') {
        const dirFiles = fs.readdirSync(currentDir)
        const foundFiles = dirFiles.filter((file) => expectationSet.has(file))
        if (foundFiles.length > 0) {
            if (!Array.isArray(expectations)) {
                return path.join(currentDir, foundFiles[0]) as FindUpReturnType<T>
            }
            return foundFiles.map((file) => path.join(currentDir, file)) as FindUpReturnType<T>
        }
        currentDir = path.dirname(currentDir)
    }
    return (Array.isArray(expectations) ? [] : undefined) as FindUpReturnType<T>
}
