import { INIT_COIN_TYPE, MnemonicKey } from '@initia/initia.js'
import { Ed25519Keypair } from '@mysten/sui/keypairs/ed25519'
import { Keypair } from '@solana/web3.js'
import { KeyPair, deriveEd25519Path, keyPairFromSeed, mnemonicToHDSeed } from '@ton/crypto'
import { WalletContractV4 } from '@ton/ton'
import * as aptos from 'aptos'
import * as bip39 from 'bip39'
import * as ed25519HdKey from 'ed25519-hd-key'
import { ethers } from 'ethers'

import { ChainType } from '@layerzerolabs/lz-definitions'

import { hexlify, trim0x } from './format'

/**
 * Interface representing an account mnemonic.
 */
export interface AccountMnemonic {
    /**
     * The mnemonic phrase.
     */
    mnemonic: string

    /**
     * The derivation path.
     */
    path: string

    /**
     * The private key (optional).
     */
    privateKey?: string

    /**
     * The address (optional).
     */
    address?: string
}

/**
 * Gets the BIP-0044 derivation path for a given chain type.
 *
 * @param {ChainType} chainType - The chain type.
 * @param {number} account - The account index.
 * @param {number} change - The change index.
 * @param {number} index - The address index.
 * @returns {string} The BIP-0044 derivation path.
 * @throws {Error} If the chain type is unsupported.
 */
export function getBIP044Path(chainType: ChainType, account: number, change: number, index: number): string {
    // CAUTION: the path format is different for each chain
    // https://github.com/bitcoin/bips/blob/master/bip-0044.mediawiki
    //
    // The "m/44'/637'/0'/0'/0'" path is known as a hardened derivation path, while the "m/44'/637'/0'/0/0" path is a non-hardened derivation path.
    // The technical benefit of using a hardened derivation path is enhanced security.
    // In BIP32, a hardened derivation is denoted by an apostrophe ('), which indicates that the child private key should be derived in a way
    // that makes it computationally infeasible to derive the parent private key from it. This additional level of security
    // protects the mnemonic phrase and its derived private keys even if one of the derived private keys is compromised.
    // By using a hardened derivation path, like "m/44'/637'/0'/0'/0'", each level of the path requires a unique private key derivation,
    // making it more difficult to infer the parent private key from the child private key. This is particularly important when dealing with
    // hierarchical deterministic wallets, as it helps protect funds across multiple accounts or purposes.

    switch (chainType) {
        case ChainType.EVM:
            // https://github.com/ethers-io/ethers.js/blob/main/src.ts/wallet/hdwallet.ts
            return `m/44'/60'/${account}'/${change}/${index}`
        case ChainType.APTOS:
            // https://github.com/aptos-labs/aptos-core/blob/main/ecosystem/typescript/sdk/src/aptos_account.ts
            return `m/44'/637'/${account}'/${change}'/${index}'`
        case ChainType.SOLANA:
            // https://github.com/solana-labs/solana/blob/master/sdk/src/derivation_path.rs
            return `m/44'/501'/${account}'/${change}'`
        case ChainType.TON:
            // https://github.com/satoshilabs/slips/blob/master/slip-0044.md#registered-coin-types
            return `m/44'/607'/${account}'/${change}/${index}`
        default:
            throw new Error(`Unsupported chain: ${chainType}`)
    }
}

/**
 * Gets an EVM account from a mnemonic phrase.
 *
 * @param {string} mnemonic - The mnemonic phrase.
 * @param {string} [path="m/44'/60'/0'/0/0"] - The derivation path.
 * @returns {AccountMnemonic} The EVM account mnemonic.
 */
export function getEvmAccountFromMnemonic(mnemonic: string, path = "m/44'/60'/0'/0/0"): AccountMnemonic {
    const wallet = ethers.Wallet.fromMnemonic(mnemonic, path)
    return {
        mnemonic,
        path,
        privateKey: wallet.privateKey,
        address: wallet.address,
    }
}

/**
 * Gets an Aptos account from a mnemonic phrase.
 *
 * @param {string} mnemonic - The mnemonic phrase.
 * @param {string} [path="m/44'/637'/0'/0'/0'"] - The derivation path.
 * @returns {AccountMnemonic} The Aptos account mnemonic.
 * @throws {Error} If the derivation path is invalid.
 */
export function getAptosAccountFromMnemonic(mnemonic: string, path = "m/44'/637'/0'/0'/0'"): AccountMnemonic {
    //https://aptos.dev/guides/building-your-own-wallet/#creating-an-aptos-account
    if (!aptos.AptosAccount.isValidPath(path)) {
        throw new Error(`Invalid derivation path: ${path}`)
    }
    const normalizeMnemonics = mnemonic
        .trim()
        .split(/\s+/)
        .map((part) => part.toLowerCase())
        .join(' ')
    {
        const { key } = aptos.derivePath(path, trim0x(hexlify(bip39.mnemonicToSeedSync(normalizeMnemonics))))
        const account = new aptos.AptosAccount(new Uint8Array(key)).toPrivateKeyObject()
        return {
            mnemonic,
            path,
            privateKey: account.privateKeyHex,
            address: account.address,
        }
    }
}

/**
 * Gets an Initia account from a mnemonic phrase.
 *
 * @param {string} mnemonic - The mnemonic phrase.
 * @param {string} [path="m/44'/118'/0'/0/0"] - The derivation path.
 * @returns {AccountMnemonic} The Initia account mnemonic.
 */
export function getInitiaAccountFromMnemonic(mnemonic: string, path = "m/44'/118'/0'/0/0"): AccountMnemonic {
    const [_, coinType, account, __, index] = path.match(/\d+/g)?.map(Number) ?? [44, 118, 0, 0, 0]
    const normalizeMnemonics = mnemonic
        .trim()
        .split(/\s+/)
        .map((part) => part.toLowerCase())
        .join(' ')
    const key = new MnemonicKey({
        mnemonic: normalizeMnemonics,
        coinType,
        account,
        index,
        eth: coinType === INIT_COIN_TYPE,
    })
    {
        return {
            mnemonic,
            path,
            privateKey: key.privateKey.toString('hex'),
            address: key.accAddress,
        }
    }
}

/**
 * Gets a Solana account from a mnemonic phrase.
 *
 * @param {string} mnemonic - The mnemonic phrase.
 * @param {string} [path="m/44'/501'/0'/0'"] - The derivation path.
 * @returns {AccountMnemonic} The Solana account mnemonic.
 */
export function getSolanaAccountFromMnemonic(mnemonic: string, path = "m/44'/501'/0'/0'"): AccountMnemonic {
    const seed = bip39.mnemonicToSeedSync(mnemonic, '') // (mnemonic, password)
    const keyPair = Keypair.fromSeed(ed25519HdKey.derivePath(path, seed.toString('hex')).key)
    return {
        mnemonic,
        path,
        privateKey: ethers.utils.hexlify(keyPair.secretKey),
        address: keyPair.publicKey.toBase58(),
    }
}

export function getPlaceholderAccountFromMnemonic(mnemonic: string, path = "m/44'/784'/0'/0'/0'"): AccountMnemonic {
    const signer = Ed25519Keypair.deriveKeypair(mnemonic, path)
    return {
        mnemonic,
        path,
        privateKey: signer.getSecretKey(),
        address: signer.toSuiAddress(),
    }
}

/**
 * Gets a TON account from a mnemonic phrase.
 *
 * @param {string} mnemonic - The mnemonic phrase.
 * @param {string} [path="m/44'/607'/0'/0'/0'"] - The derivation path.
 * @param {number} [workchain=0] - The workChain ID.
 * @returns {Promise<AccountMnemonic>} A promise that resolves to the TON account mnemonic.
 */
export async function getTonAccountFromMnemonic(
    mnemonic: string,
    path = "m/44'/607'/0'/0'/0'",
    workchain = 0
): Promise<AccountMnemonic> {
    const { wallet, keyPair } = await getTonWalletFromMnemonic(mnemonic, path, workchain)
    return {
        mnemonic,
        path,
        privateKey: ethers.utils.hexlify(keyPair.secretKey),
        address: wallet.address.toString({ bounceable: false, urlSafe: true }),
    }
}

/**
 * Gets a key pair from a mnemonic phrase for a given chain type.
 *
 * @param {ChainType} chainType - The chain type.
 * @param {string} mnemonic - The mnemonic phrase.
 * @param {string} [path] - The derivation path.
 * @returns {Promise<AccountMnemonic>} A promise that resolves to the account mnemonic.
 * @throws {Error} If the chain type is unsupported.
 */
export async function getKeypairFromMnemonic(
    chainType: ChainType,
    mnemonic: string,
    path?: string
): Promise<AccountMnemonic> {
    switch (chainType) {
        case ChainType.EVM:
            return getEvmAccountFromMnemonic(mnemonic, path)
        case ChainType.APTOS:
            return getAptosAccountFromMnemonic(mnemonic, path)
        case ChainType.INITIA:
            return getInitiaAccountFromMnemonic(mnemonic, path)
        case ChainType.SOLANA:
            return getSolanaAccountFromMnemonic(mnemonic, path)
        case ChainType.TON:
            return getTonAccountFromMnemonic(mnemonic, path)
        case ChainType.SUI:
            return getPlaceholderAccountFromMnemonic(mnemonic, path)
        default:
            throw new Error(`Unsupported chain: ${chainType}`)
    }
}

/**
 * Gets a TON wallet from a mnemonic phrase.
 *
 * @param {string} mnemonic - The mnemonic phrase.
 * @param {string} [path="m/44'/607'/0'/0'/0'"] - The derivation path.
 * @param {number} [workchain=0] - The workChain ID.
 * @returns {Promise<{ wallet: WalletContractV4; keyPair: KeyPair }>} A promise that resolves to the TON wallet and key pair.
 */
export async function getTonWalletFromMnemonic(
    mnemonic: string,
    path = "m/44'/607'/0'/0'/0'",
    workchain = 0
): Promise<{ wallet: WalletContractV4; keyPair: KeyPair }> {
    const seed: Buffer = await mnemonicToHDSeed(mnemonic.split(' '))
    const indices: number[] = toPathArray(path)
    const derivedSeed: Buffer = await deriveEd25519Path(seed, indices)
    const keyPair: KeyPair = keyPairFromSeed(derivedSeed)
    return {
        wallet: WalletContractV4.create({ publicKey: keyPair.publicKey, workchain }),
        keyPair,
    }
}

/**
 * Converts a path string to an array of numbers.
 * TON currently supports hardened paths only: https://github.com/ton-org/ton-crypto/blob/master/src/hd/ed25519.ts#L32
 *
 * @param {string} path - The path string to convert.
 * @returns {number[]} An array of numbers representing the path.
 * @throws {Error} If the path is invalid.
 */
function toPathArray(path: string): number[] {
    if (!/^[mM]'?/.test(path)) {
        throw new Error('Path must start with "m" or "M"')
    }
    const parts = path.replace(/^[mM]'?\//, '').split('/')
    const ret: number[] = Array<number>(parts.length)
    for (let i = 0; i < parts.length; i++) {
        const tmp = /(\d+)[hH']/.exec(parts[i])
        if (tmp === null) {
            throw new Error('Invalid input')
        }
        ret[i] = parseInt(tmp[1], 10)

        if (ret[i] >= 0x80000000) {
            throw new Error('Invalid child index')
        }
    }
    return ret
}
