import module from 'module'

/**
 * Enables TypeScript support for the specified file or module.
 *
 * @param relativeToPath - The path relative to which the TypeScript module should be resolved.
 * @returns void
 *
 * @remarks
 * This function enables TypeScript support by registering the 'ts-node' module and configuring it with the provided options.
 * The 'ts-node' module allows for on-the-fly TypeScript transpilation without the need for a separate build step.
 *
 * @example
 * enableTS(process.cwd());
 */
export function enableTS(relativeToPath: string): void {
    // WARNING: require('ts-node') will cause '[ERROR] Unterminated template (867:31) [plugin commonjs]' in some cases
    //   this error can be eliminated by assigning the name to a variable and require that variable
    const moduleName = 'ts-node'
    const require = module.createRequire(relativeToPath)
    const modulePath = require.resolve(moduleName)

    // eslint-disable-next-line @typescript-eslint/no-unsafe-assignment
    const tsnode = require(modulePath)

    // eslint-disable-next-line @typescript-eslint/no-unsafe-call, @typescript-eslint/no-unsafe-member-access
    tsnode.register({
        transpileOnly: true,
        typeCheck: false,
    })
}

/**
 * Loads a JavaScript or TypeScript module.
 *
 * @param fileName - The name of the file to load.
 * @param relativeToPath - The path relative to which the file should be resolved.
 * @returns The loaded module.
 *
 * @example
 * // Load a JavaScript module
 * const myModule = await loadJSorTS('myModule.js', '/path/to/file.js');
 *
 * // Load a TypeScript module
 * const myModule = await loadJSorTS('myModule.ts', '/path/to/file.js');
 */
export async function loadJSorTS(fileName: string, relativeToPath: string): Promise<any> {
    /* eslint-disable @typescript-eslint/no-unsafe-return, @typescript-eslint/restrict-template-expressions */
    const require = module.createRequire(relativeToPath)
    const modulePath = require.resolve(fileName)

    if (fileName.endsWith('.ts')) {
        enableTS(relativeToPath)
        return require(modulePath)
    } else if (fileName.endsWith('.mjs')) {
        return import(modulePath)
    } else if (fileName.endsWith('.cjs')) {
        return Promise.resolve(require(modulePath))
    } else if (fileName.endsWith('.js')) {
        try {
            return await Promise.resolve(require(modulePath))
        } catch (requireError) {
            try {
                return await import(modulePath)
            } catch (importError) {
                throw new Error(
                    `Failed to load module: ${fileName}. Require error: ${requireError}. Import error: ${importError}`
                )
            }
        }
    } else {
        throw new Error(`Unsupported file extension: ${fileName}`)
    }
    /* eslint-enable @typescript-eslint/no-unsafe-return, @typescript-eslint/restrict-template-expressions */
}
