import module from 'module'

/**
 * Returns the directory name of a path.
 *
 * @param {string} path - The path to get the directory name from.
 * @returns {string} The directory name of the path.
 */
export function dirname(path: string): string {
    const match = path.match(/(.*)([\\/][^\\/]+)[/\\]?$/)
    const [, basePath] = match ?? []
    const dirname = typeof basePath !== 'undefined' ? basePath : path
    return dirname
}

/**
 * Gets the current stack trace.
 *
 * @param {number} [stackTraceLimit=Infinity] - The stack trace limit.
 * @returns {string | undefined} The current stack trace.
 */
function getStackTrace(stackTraceLimit = Infinity): string | undefined {
    const oldLimit = Error.stackTraceLimit
    Error.stackTraceLimit = stackTraceLimit
    const retval = new Error().stack
    Error.stackTraceLimit = oldLimit
    return retval
}

/**
 * Gets the caller of the current function.
 *
 * @returns {string | undefined} The caller of the current function.
 */
function getCaller(): string | undefined {
    const lines = (getStackTrace(10) ?? '').split('\n')
    // Error:
    //     at getStackTrace
    //     at getCaller
    //     at <caller of getCaller>
    //     at <expected caller>
    if (lines.length > 1 + 1 + 1 + 1) {
        const line = lines[4]
        const m = line.match(/^.*\(([^:]*)[^)]*\)/)
        if (m) {
            return m[1]
        }
    }
    return undefined
}

/**
 * Returns the root path of a package.
 *
 * @param {string} packageName - The name of the package.
 * @param {string} [relativeToPath] - The path to resolve the package root relative to.
 * @returns {string} The root path of the package.
 */
export function pkgroot(packageName: string, relativeToPath?: string): string {
    if (relativeToPath === undefined) {
        relativeToPath = getCaller()
        if (relativeToPath === undefined) {
            relativeToPath = __filename
        }
    }

    const filepath = module.createRequire(relativeToPath).resolve(`${packageName}/package.json`)
    const packagePath = dirname(filepath)
    // https://github.com/yarnpkg/berry/blob/f67dda88fe9d0a892c44af923cbbc50bfe454e0e/packages/docusaurus/docs/advanced/03-pnp/pnp-spec.md
    // In order to properly represent packages listing peer dependencies, Yarn relies on a concept
    // called Virtual Packages. Their most notable property is that they all have different paths
    // (so that Node.js instantiates them as many times as needed), while still being baked by the
    // same concrete folder on disk.
    return packagePath.replace(/.yarn\/([^/]*\/)?(__virtual__|\$\$virtual)\/[^/]*\/\d*\//, '')
}
