import dayjs from 'dayjs'
import pc from 'picocolors'
import { pino } from 'pino'

let logger: pino.Logger | undefined = undefined

export type Logger = pino.Logger

/**
 * Gets the current stack trace.
 *
 * @returns {string | undefined} The current stack trace.
 */
function getStackTrace(): string | undefined {
    const oldLimit = Error.stackTraceLimit
    Error.stackTraceLimit = Infinity
    const retval = new Error().stack
    Error.stackTraceLimit = oldLimit
    return retval
}

/**
 * Creates a replacer function for handling circular references in JSON.stringify.
 * details: https://developer.mozilla.org/en-US/docs/Web/JavaScript/Reference/Errors/Cyclic_object_value
 *
 * @returns {(key: string, value: unknown) => unknown} The replacer function.
 */
export function getCircularReplacer(): (key: string, value: unknown) => unknown {
    const ancestors: unknown[] = []
    return function (this: unknown, _key: string, value: unknown) {
        if (typeof value !== 'object' || value === null) {
            return value
        }
        // `this` is the object that value is contained in,
        // i.e., its direct parent.
        while (ancestors.length > 0 && ancestors.at(-1) !== this) {
            ancestors.pop()
        }
        if (ancestors.includes(value)) {
            return '[Circular]'
        }
        ancestors.push(value)
        return value
    }
}

/**
 * Extracts caller information from a stack trace line.
 *
 * @param {string} line - The stack trace line.
 * @returns {string} The extracted caller information.
 */
function extractCallerInfo(line: string): string {
    for (const pattern of [/\((.*?:\d+:\d+)\)$/, /at (.*?:\d+:\d+)$/]) {
        const m = line.match(pattern)
        if (m === null) {
            continue
        }
        const [, fileInfoLine] = m
        return fileInfoLine
    }
    return '<unknown>'
}

function getCaller(pattern: RegExp): string {
    const stack = getStackTrace() ?? ''

    const stackLines = stack.split('\n')

    const index =
        stackLines.findIndex((line) => {
            return line.match(pattern)
        }) + 1

    let fileInfo = '<unknown>'
    if (stackLines.length > index) {
        const line = stackLines[index]
        fileInfo = extractCallerInfo(line)
    }
    return fileInfo
}

/**
 * Initializes the logger with the specified log level.
 *
 * @param {string} level - The log level.
 */
export function initLogger(level: string): void {
    if (!logger) {
        logger = createLogger(level)
    }
}

// Define custom colors for log levels
const levelColors: { [key: string]: (msg: string) => string } = {
    TRACE: pc.reset,
    DEBUG: pc.reset,
    INFO: pc.green,
    WARN: pc.yellow,
    ERROR: pc.red,
    FATAL: pc.red,
}

// Create a custom stream for logging with colors
const customStream = {
    write: (msg: string): void => {
        try {
            const customLogger = (output: string) => {
                if (typeof process !== 'undefined') {
                    process.stdout.write(output + '\n') // Works in Node.js
                } else {
                    console.log(output) // Works in Browsers
                }
            }
            const logObj = JSON.parse(msg) // Parse the log message
            const { level, msg: message, time } = logObj

            const newMsgs: string[] = message.split('#caller#')
            // Format the time
            const formattedTime = dayjs(time).format('YYYY-MM-DD HH:mm:ss')

            // Get the appropriate color function (default to reset)
            const colorFn = levelColors[level] || pc.reset

            newMsgs.forEach((newMsg) => {
                customLogger(colorFn(`[${formattedTime}] [${level}] ${newMsg}`))
            })
        } catch (error) {
            console.error('Failed to process log:', msg)
        }
    },
}

/**
 * Creates a new logger with the specified log level.
 *
 * @param {string} level - The log level.
 * @returns {Logger} The created logger.
 */
export function createLogger(level: string): pino.Logger {
    const logger = pino(
        {
            level,
            base: undefined,
            // customLevels: customLevels.levels,
            // timestamp: () => `,"time":"${formatTime(Date.now())}"`,
            formatters: {
                level(levelLabel, levelNumber) {
                    return { level: levelLabel.toUpperCase(), levelNumber: levelNumber } // 让日志级别大写
                },
            },
            hooks: {
                logMethod(inputArgs, method, level) {
                    const [msg, ...args] = inputArgs
                    let newMsg = msg
                    let caller = ''
                    if (level >= 50) {
                        caller = getCaller(/lib\/tools.js/)
                        newMsg = `${caller}#caller#${msg} `
                    }
                    // eslint-disable-next-line @typescript-eslint/no-unsafe-argument,@typescript-eslint/no-unsafe-assignment
                    method.apply(this, [newMsg, ...args, caller])
                    // method.apply(this, inputArgs)
                },
            },
        },
        customStream
    )
    return logger
}

/**
 * Gets the current logger instance.
 *
 * @returns {Logger} The current logger instance.
 * @throws {Error} If the logger is not initialized.
 */
export function getLogger(): Logger {
    initLogger(process.env.LZ_LOG ?? 'info')
    if (!logger) {
        throw new Error('Logger is not initialized')
    }
    return logger
}

const exportsObject: {
    getCircularReplacer?: (key: unknown, value: unknown) => unknown
} = {}

if (process.env.NODE_ENV === 'test') {
    exportsObject.getCircularReplacer = getCircularReplacer
}
export default exportsObject
