import { Bytes, Hex } from './types'

/**
 * Interface representing the options for padding.
 */
interface PadOptions {
    /**
     * The direction of the padding. Defaults to undefined.
     */
    dir?: 'left' | 'right' | undefined

    /**
     * The size to pad to. Defaults to 32.
     */
    size?: number | null | undefined
}

/**
 * Type representing the return type of the padify function.
 */
export type PadReturnType<value extends Bytes | Hex> = value extends Hex ? Hex : Bytes

/**
 * Type representing an error when the size exceeds the padding size.
 */
export type SizeExceedsPaddingSizeErrorType = SizeExceedsPaddingSizeError & {
    name: 'SizeExceedsPaddingSizeError'
}

/**
 * Class representing an error when the size exceeds the padding size.
 */
export class SizeExceedsPaddingSizeError extends Error {
    override name = 'SizeExceedsPaddingSizeError'
    constructor({ size, targetSize, type }: { size: number; targetSize: number; type: 'hex' | 'bytes' }) {
        super(
            `${type.charAt(0).toUpperCase()}${type
                .slice(1)
                .toLowerCase()} size (${size}) exceeds padding size (${targetSize})`
        )
    }
}

/**
 * Pads a hexadecimal string or byte array to a specified size.
 *
 * @param {Bytes | Hex} hexOrBytes - The hexadecimal string or byte array to pad.
 * @param {PadOptions} [options] - The padding options.
 * @param {'left' | 'right'} [options.dir] - The direction of the padding. Defaults to undefined.
 * @param {number} [options.size=32] - The size to pad to. Defaults to 32.
 * @returns {PadReturnType<Bytes | Hex>} The padded hexadecimal string or byte array.
 * @throws {SizeExceedsPaddingSizeError} If the size exceeds the padding size.
 */
export function padify<value extends Bytes | Hex>(
    hexOrBytes: value,
    { dir, size = 32 }: PadOptions = {}
): PadReturnType<value> {
    if (typeof hexOrBytes === 'string') {
        return padHex(hexOrBytes, { dir, size }) as PadReturnType<value>
    }
    return padBytes(hexOrBytes, { dir, size }) as PadReturnType<value>
}

/**
 * Pads a hexadecimal string to a specified size.
 *
 * @param {Hex} hex - The hexadecimal string to pad.
 * @param {PadOptions} [options] - The padding options.
 * @param {'left' | 'right'} [options.dir] - The direction of the padding. Defaults to undefined.
 * @param {number} [options.size=32] - The size to pad to. Defaults to 32.
 * @returns {Hex} The padded hexadecimal string.
 * @throws {SizeExceedsPaddingSizeError} If the size exceeds the padding size.
 */
function padHex(hex: Hex, { dir, size = 32 }: PadOptions = {}): Hex {
    if (size === null) return hex
    const value = hex.replace('0x', '')
    if (value.length > size * 2)
        throw new SizeExceedsPaddingSizeError({
            size: Math.ceil(value.length / 2),
            targetSize: size,
            type: 'hex',
        })

    return `0x${value[dir === 'right' ? 'padEnd' : 'padStart'](size * 2, '0')}`
}

/**
 * Pads a byte array to a specified size.
 *
 * @param {Bytes} bytes - The byte array to pad.
 * @param {PadOptions} [options] - The padding options.
 * @param {'left' | 'right'} [options.dir] - The direction of the padding. Defaults to undefined.
 * @param {number} [options.size=32] - The size to pad to. Defaults to 32.
 * @returns {Bytes} The padded byte array.
 * @throws {SizeExceedsPaddingSizeError} If the size exceeds the padding size.
 */
function padBytes(bytes: Bytes, { dir, size = 32 }: PadOptions = {}): Bytes {
    if (size === null) return bytes
    if (bytes.length > size)
        throw new SizeExceedsPaddingSizeError({
            size: bytes.length,
            targetSize: size,
            type: 'bytes',
        })
    const paddedBytes = new Uint8Array(size)
    for (let i = 0; i < size; i++) {
        const padEnd = dir === 'right'
        paddedBytes[padEnd ? i : size - i - 1] = bytes[padEnd ? i : bytes.length - i - 1]
    }
    return paddedBytes
}
