import memoizee, { Options } from 'memoizee'

export function Memoizee<F extends (...args: any[]) => any>(options?: Options<F>): MethodDecorator {
    return function (target: object, propertyKey: string | symbol, descriptor: TypedPropertyDescriptor<F>): void {
        const originalMethod = descriptor.value

        if (typeof originalMethod !== 'function') {
            throw new Error(`@Memoizee decorator can only be applied to methods.`)
        }

        const isAsyncFunction = originalMethod.constructor.name === 'AsyncFunction'
        const memoizeOptions: Options<F> = {
            ...options,
            promise: options?.promise ?? isAsyncFunction,
        }

        if (!isAsyncFunction) {
            // Check if the function uses a Node.js-style callback
            const originalMethodStr = originalMethod.toString()
            if (originalMethodStr.includes('callback') || originalMethodStr.includes('cb')) {
                memoizeOptions.async = true
            }
        }

        const memoizedFn = memoizee(originalMethod, memoizeOptions)
        const fn = memoizedFn as F & { clear: () => void }
        fn.clear = (): void => {
            memoizedFn.clear()
        }

        descriptor.value = fn
    } as MethodDecorator
}
